module mux_4to1 (
  input  wire [3:0] iDataIn,
  input  wire [1:0] iSel,
  output wire       oDataOut
);
  assign oDataOut = iDataIn[iSel];
endmodule

module decoder_3to8 (
  input  wire [2:0] iAddr,
  input  wire       iEnable,
  output wire [7:0] oDecOut
);
  assign oDecOut = iEnable ? (8'b0000_0001 << iAddr) : 8'b0;
endmodule

module compare_4bit (
  input  wire [3:0] iA,
  input  wire [3:0] iB,
  output wire       oGt,
  output wire       oEq,
  output wire       oLt
);
  assign oGt = (iA > iB);
  assign oEq = (iA == iB);
  assign oLt = (iA < iB);
endmodule

module full_adder (
  input  wire iA,
  input  wire iB,
  input  wire iCin,
  output wire oSum,
  output wire oCout
);
  assign oSum  = iA ^ iB ^ iCin;
  assign oCout = (iA & iB) | (iA & iCin) | (iB & iCin);
endmodule

module rca_4bit (
  input  wire [3:0] iA,
  input  wire [3:0] iB,
  input  wire       iCin,
  output wire [3:0] oSum,
  output wire       oCout
);
  wire [4:0] wCarry;

  assign wCarry[0] = iCin;
  assign oCout = wCarry[4];

  full_adder u_fa0 (.iA(iA[0]), .iB(iB[0]), .iCin(wCarry[0]), .oSum(oSum[0]), .oCout(wCarry[1]));
  full_adder u_fa1 (.iA(iA[1]), .iB(iB[1]), .iCin(wCarry[1]), .oSum(oSum[1]), .oCout(wCarry[2]));
  full_adder u_fa2 (.iA(iA[2]), .iB(iB[2]), .iCin(wCarry[2]), .oSum(oSum[2]), .oCout(wCarry[3]));
  full_adder u_fa3 (.iA(iA[3]), .iB(iB[3]), .iCin(wCarry[3]), .oSum(oSum[3]), .oCout(wCarry[4]));
endmodule

module dff_sync_rst (
  input  wire iClk,
  input  wire iRstn,
  input  wire iD,
  output reg  oQ
);
  always @(posedge iClk) begin
    if (!iRstn) oQ <= 1'b0;
    else        oQ <= iD;
  end
endmodule

module dff_async_rst (
  input  wire iClk,
  input  wire iRstn,
  input  wire iD,
  output reg  oQ
);
  always @(posedge iClk or negedge iRstn) begin
    if (!iRstn) oQ <= 1'b0;
    else        oQ <= iD;
  end
endmodule

module counter_4bit (
  input  wire       iClk,
  input  wire       iRstn,
  input  wire       iEnable,
  output reg  [3:0] oCnt
);
  always @(posedge iClk) begin
    if (!iRstn)      oCnt <= 4'd0;
    else if (iEnable) oCnt <= oCnt + 4'd1;
  end
endmodule

module counter_updown_4bit (
  input  wire       iClk,
  input  wire       iRstn,
  input  wire       iEnable,
  input  wire       iUpDown,
  output reg  [3:0] oCnt
);
  always @(posedge iClk) begin
    if (!iRstn) oCnt <= 4'd0;
    else if (iEnable) oCnt <= iUpDown ? oCnt + 4'd1 : oCnt - 4'd1;
  end
endmodule

module counter_mod10 (
  input  wire       iClk,
  input  wire       iRstn,
  input  wire       iEnable,
  output reg  [3:0] oCnt,
  output reg        oTick
);
  always @(posedge iClk) begin
    if (!iRstn) begin
      oCnt <= 4'd0;
      oTick <= 1'b0;
    end
    else begin
      oTick <= 1'b0;
      if (iEnable && oCnt == 4'd9) begin
        oCnt <= 4'd0;
        oTick <= 1'b1;
      end
      else if (iEnable) oCnt <= oCnt + 4'd1;
    end
  end
endmodule

module shift_sipo_8bit (
  input  wire       iClk,
  input  wire       iRstn,
  input  wire       iSerialIn,
  output reg  [7:0] oParallelOut
);
  always @(posedge iClk) begin
    if (!iRstn) oParallelOut <= 8'd0;
    else        oParallelOut <= {oParallelOut[6:0], iSerialIn};
  end
endmodule

