module sync_2ff (
  input  wire iClkDst,
  input  wire iRstn,
  input  wire iSigIn,
  output wire oSigOut
);
  reg rSync0, rSync1;

  always @(posedge iClkDst) begin
    if (!iRstn) {rSync1, rSync0} <= 2'b00;
    else        {rSync1, rSync0} <= {rSync0, iSigIn};
  end

  assign oSigOut = rSync1;
endmodule

module sync_edge_detect (
  input  wire iClkDst,
  input  wire iRstn,
  input  wire iSigIn,
  output wire oPulseOut
);
  reg rSync0, rSync1, rSync1Dly;

  always @(posedge iClkDst) begin
    if (!iRstn) {rSync1Dly, rSync1, rSync0} <= 3'b000;
    else        {rSync1Dly, rSync1, rSync0} <= {rSync1, rSync0, iSigIn};
  end

  assign oPulseOut = rSync1 & ~rSync1Dly;
endmodule

module async_fifo #(
  parameter DATA_WIDTH = 8,
  parameter ADDR_WIDTH = 4
) (
  input  wire                  iClkW,
  input  wire                  iRstnW,
  input  wire                  iWrEn,
  input  wire [DATA_WIDTH-1:0] iWrData,
  input  wire                  iClkR,
  input  wire                  iRstnR,
  input  wire                  iRdEn,
  output reg  [DATA_WIDTH-1:0] oRdData,
  output wire                  oFull,
  output wire                  oEmpty
);
  localparam DEPTH = 1 << ADDR_WIDTH;

  reg [DATA_WIDTH-1:0] rMem [0:DEPTH-1];
  reg [ADDR_WIDTH:0] rWrBin, rRdBin, rWrGray, rRdGray;
  reg [ADDR_WIDTH:0] rRdGrayW0, rRdGrayW1, rWrGrayR0, rWrGrayR1;

  wire wWrFire = iWrEn & ~oFull;
  wire wRdFire = iRdEn & ~oEmpty;
  wire [ADDR_WIDTH:0] wWrBinNext = rWrBin + wWrFire;
  wire [ADDR_WIDTH:0] wRdBinNext = rRdBin + wRdFire;
  wire [ADDR_WIDTH:0] wWrGrayNext = (wWrBinNext >> 1) ^ wWrBinNext;
  wire [ADDR_WIDTH:0] wRdGrayNext = (wRdBinNext >> 1) ^ wRdBinNext;

  assign oFull = (wWrGrayNext == {~rRdGrayW1[ADDR_WIDTH:ADDR_WIDTH-1], rRdGrayW1[ADDR_WIDTH-2:0]});
  assign oEmpty = (wRdGrayNext == rWrGrayR1);

  always @(posedge iClkW or negedge iRstnW) begin
    if (!iRstnW) {rWrBin, rWrGray} <= {2*(ADDR_WIDTH+1){1'b0}};
    else begin
      if (wWrFire) rMem[rWrBin[ADDR_WIDTH-1:0]] <= iWrData;
      rWrBin <= wWrBinNext;
      rWrGray <= wWrGrayNext;
    end
  end

  always @(posedge iClkR or negedge iRstnR) begin
    if (!iRstnR) begin
      {rRdBin, rRdGray} <= {2*(ADDR_WIDTH+1){1'b0}};
      oRdData <= {DATA_WIDTH{1'b0}};
    end
    else begin
      if (wRdFire) oRdData <= rMem[rRdBin[ADDR_WIDTH-1:0]];
      rRdBin <= wRdBinNext;
      rRdGray <= wRdGrayNext;
    end
  end

  always @(posedge iClkW or negedge iRstnW) begin
    if (!iRstnW) {rRdGrayW1, rRdGrayW0} <= {2*(ADDR_WIDTH+1){1'b0}};
    else         {rRdGrayW1, rRdGrayW0} <= {rRdGrayW0, rRdGray};
  end

  always @(posedge iClkR or negedge iRstnR) begin
    if (!iRstnR) {rWrGrayR1, rWrGrayR0} <= {2*(ADDR_WIDTH+1){1'b0}};
    else         {rWrGrayR1, rWrGrayR0} <= {rWrGrayR0, rWrGray};
  end
endmodule

module fsm_moore_3state_3p (
  input  wire       iClk,
  input  wire       iRstn,
  input  wire       iStart,
  input  wire       iDoneIn,
  output reg  [1:0] oState,
  output reg        oBusy,
  output reg        oComplete
);
  localparam IDLE = 2'd0, READY = 2'd1, DONE = 2'd2;
  reg [1:0] rNxtState;

  always @(posedge iClk) begin
    if (!iRstn) oState <= IDLE;
    else        oState <= rNxtState;
  end

  always @(*) begin
    rNxtState = oState;
    case (oState)
      IDLE:  if (iStart)  rNxtState = READY;
      READY: if (iDoneIn) rNxtState = DONE;
      DONE:  rNxtState = IDLE;
      default: rNxtState = IDLE;
    endcase
  end

  always @(*) begin
    oBusy = (oState == READY);
    oComplete = (oState == DONE);
  end
endmodule
